//vip.opstream14.com/20230315/33730_c549d7fe/index.m3u8"}]}],"time":"107 Phút","description":"Khi Kenny, anh trai của Betty Anne Waters, bị bắt vì tội giết người và bị kết án chung thân vào năm 1983, Betty Anne, một người vợ ở Massachusetts và là mẹ của hai đứa con, đã cống hiến cuộc đời mình để lật ngược bản án giết người. Tin chắc rằng anh trai mình vô tội, Betty Anne đã vượt qua các trường trung học, đại học và cuối cùng là trường luật trong hành trình 18 năm giải thoát Kenny. Với sự giúp đỡ của người bạn thân nhất Abra Rice, Betty Anne tìm hiểu kỹ bằng chứng đáng ngờ do cảnh sát thị trấn nhỏ Nancy Taylor thu thập, tỉ mỉ lần lại các bước dẫn đến việc bắt giữ Kenny. Niềm tin vào anh trai - và hành trình tìm kiếm sự thật - thúc đẩy Betty Anne và nhóm của cô khám phá sự thật và sử dụng bằng chứng DNA với hy vọng minh oan cho Kenny.","tmdb":{"type":"movie","id":"45094","season":null,"vote_average":7.066,"vote_count":633},"modified":"2023-03-15T22:57:23.000Z","_image_preserved":true},{"id":"6411eb80e549a2bfea76f8be","_id":"6411eb80e549a2bfea76f8be","title":"Win It All","origin_name":"Win It All","slug":"win-it-all","year":2017,"type":"single","genre":[{"id":"620a221de0fc277084dfd1c1","name":"Hài Hước","slug":"hai-huoc"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Win It All - Được Ăn Cả, Ngã Về Không - 2017","link_embed":"https://vip.opstream14.com/share/5056e88bd52775b023eb781848b37594","link_m3u8":"https://vip.opstream14.com/20230315/33729_54d15e2a/index.m3u8"}]}],"time":"88 Phút","description":"Một người nghiện cờ bạc đối mặt với xung đột khi được giao giữ một đống tiền không phải của mình.","tmdb":{"type":"movie","id":"397442","season":null,"vote_average":5